import React from "react";
import { useUploader } from "../MainUploader";
import { Button, Flex, Image, Text } from "../../../../";

const MultipleImageUploader = () => {
    const { onPick, files, removeFile, disabled, limit, isClassicUploader } =
        useUploader();

    if (!isClassicUploader) {
        return (
            <Flex w={"full"} gap={2}>
                <Button label={"Upload"} onClick={onPick as any} disabled={disabled} />
                <Button label={`${files.length}/${limit} Selected`} outlined disabled />
            </Flex>
        );
    }

    return (
        <Flex w={"full"} gap={2}>
            {files.map((f, idx) => {
                const uri =
                    typeof f.file === "object" && "uri" in f.file ? f.file.uri : null;

                return (
                    <Flex
                        key={`${f.name}-${idx}`}
                        flexDirection={"row"}
                        justifyContent={"space-between"}
                        alignItems={"center"}
                        gap={2}
                    >
                        <Flex flexDirection={"row"} alignItems={"center"} gap={2}>
                            {uri ? <Image src={uri} alt={f.name} /> : null}
                            <Text as={"span"} textOverflow={"ellipsis"} whiteSpace={"nowrap"}>
                                {f.shortName}
                            </Text>
                        </Flex>

                        <Button
                            icon="pi pi-times"
                            size={'md'}
                            w={20}
                            severity={"danger"}
                            onClick={removeFile(idx)}
                            disabled={disabled}
                        />
                    </Flex>
                );
            })}

            <Button
                label={"Add images"}
                onClick={onPick as any}
                disabled={disabled || files.length >= limit}
            />
        </Flex>
    );
};

export default MultipleImageUploader;
